-- B) 단가행 t_prc_component_prices.note — 결정적 regexp 치환 체인
--    합가 메모 → '작업 1건 고정 금액' / prefix [siz..] 제거 / 메모 시그니처 괄호 제거
--    [..mat=MAT_N..] 코드만 제거(설명 보존) / 'A≥N'→'A N 이상' / 잔여 ≥ → '이상' / 공백 정리
--    의미(소재·색·도수·사이즈) 괄호·[..포함가]·[묶음..]은 보존. note만 읽어 note만 씀.
UPDATE t_prc_component_prices cp SET note = btrim(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(note, '\s*\([^()]*합가[^()]*(\([^()]*\)[^()]*)*\)', ' / 작업 1건 고정 금액(수량을 곱하지 않음)', 'g'), '^\[siz[^\]]*\]\s*', ''), '\s*\([^()]*(comp흡수|comp_typ|SIZ_[0-9]|MAT_[0-9]|PRD_[0-9]|규칙④|규칙[0-9]|bdl_qty|min_qty|라이브 siz|완제품비\.|완제품가 \.|중첩서브제품|소재묶음|band=|M-[0-9]+정정|행[0-9]|별도 add-on|수량무관 셋업|차원부재|DIRECT매칭|SIZ_PENDING|대표mat|규격단독|상품구분축|후니확인|=comp|추출결함|면당EA)[^()]*(\([^()]*\)[^()]*)*\)', '', 'g'), '\[([^\]]*?)\s*,?\s*mat=MAT_[0-9]+[^\]]*\]', '[\1]', 'g'), '(총제작수량|제작수량|출력매수|수량|장수)≥([0-9]+)', '\1 \2 이상', 'g'), '≥\s*([0-9]+)', '\1 이상', 'g'), '\s{2,}', ' ', 'g')), upd_dt=now()
WHERE cp.note IS NOT NULL
  AND cp.note ~ 'siz-corrected|comp_typ|PRC_COMPONENT_TYPE|round-2|clr=NULL|별색=공정|옵션=comp흡수|SIZ_[0-9]|MAT_[0-9]|PROC_[0-9]|mat_cd|siz_cd|C-[0-9]|≥'
  AND cp.note IS DISTINCT FROM (btrim(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(regexp_replace(note, '\s*\([^()]*합가[^()]*(\([^()]*\)[^()]*)*\)', ' / 작업 1건 고정 금액(수량을 곱하지 않음)', 'g'), '^\[siz[^\]]*\]\s*', ''), '\s*\([^()]*(comp흡수|comp_typ|SIZ_[0-9]|MAT_[0-9]|PRD_[0-9]|규칙④|규칙[0-9]|bdl_qty|min_qty|라이브 siz|완제품비\.|완제품가 \.|중첩서브제품|소재묶음|band=|M-[0-9]+정정|행[0-9]|별도 add-on|수량무관 셋업|차원부재|DIRECT매칭|SIZ_PENDING|대표mat|규격단독|상품구분축|후니확인|=comp|추출결함|면당EA)[^()]*(\([^()]*\)[^()]*)*\)', '', 'g'), '\[([^\]]*?)\s*,?\s*mat=MAT_[0-9]+[^\]]*\]', '[\1]', 'g'), '(총제작수량|제작수량|출력매수|수량|장수)≥([0-9]+)', '\1 \2 이상', 'g'), '≥\s*([0-9]+)', '\1 이상', 'g'), '\s{2,}', ' ', 'g')))
